const MOCK_NOTIFICATIONS = [
    { id: 1, type: 'like', user: 'sarah_j', name: 'Sarah Johnson', avatar: 'https://i.pravatar.cc/150?img=1', text: 'liked your photo', time: '2m ago', image: 'https://picsum.photos/seed/1/400', unread: true },
