import { S3Client, PutObjectCommand, GetObjectCommand } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';

const s3Client = new S3Client({
    region: process.env.AWS_REGION || 'us-east-1',
    credentials: {
        accessKeyId: process.env.AWS_ACCESS_KEY_ID || '',
        secretAccessKey: process.env.AWS_SECRET_ACCESS_KEY || '',
    },
});

const BUCKET_NAME = process.env.AWS_S3_BUCKET_NAME || 'viewer-media';

// Upload file to S3 and return the public URL
export async function uploadToS3(fileBuffer: Buffer, fileName: string, contentType: string): Promise<string> {
    const key = `uploads/${Date.now()}-${fileName}`;

    // Check if credentials exist, otherwise fallback or error
    if (!process.env.AWS_ACCESS_KEY_ID || !process.env.AWS_SECRET_ACCESS_KEY) {
        console.warn('AWS Credentials missing, cannot upload to S3.');
        return '';
    }

    try {
        const command = new PutObjectCommand({
            Bucket: BUCKET_NAME,
            Key: key,
            Body: fileBuffer,
            ContentType: contentType,
            // ACL: 'public-read', // Deprecated in many new buckets, use Bucket Policy instead strictly
        });

        await s3Client.send(command);

        // Return the CDN URL if configured, otherwise the standard S3 URL
        if (process.env.CDN_DOMAIN) {
            const cdnDomain = process.env.CDN_DOMAIN.replace(/\/$/, ''); // Remove trailing slash
            return `${cdnDomain}/${key}`;
        }

        return `https://${BUCKET_NAME}.s3.${process.env.AWS_REGION}.amazonaws.com/${key}`;
    } catch (error) {
        console.error('S3 Upload Error:', error);
        throw new Error('Failed to upload file to S3');
    }
}

// Generate a presigned URL for client-side uploads (Alternative strategy)
export async function getPresignedUploadUrl(fileName: string, contentType: string) {
    const key = `uploads/${Date.now()}-${fileName}`;
    const command = new PutObjectCommand({
        Bucket: BUCKET_NAME,
        Key: key,
        ContentType: contentType,
    });

    const url = await getSignedUrl(s3Client, command, { expiresIn: 3600 });
    return { url, key };
}

import prisma from '@/lib/prisma';
import { getCassandraClient } from '@/lib/cassandra';
import { getOrSet } from '@/lib/redis';

export type FeedItem = {
    id: string;
    type: 'post' | 'shot';
    caption: string | null;
    image: string; // compatibility field
    media: { url: string; type: string; order: number }[];
    createdAt: Date;
    user: {
        username: string;
        avatar: string | null;
        fullName: string | null;
    };
    likesCount: number;
    commentsCount: number;
    isLiked?: boolean;
    location?: string | null;
};

export const FeedService = {
    // Public: Get Feed (Cached or Fresh)
    async generateFeed(userId: string, page = 1, limit = 20): Promise<any[]> {
        const cacheKey = `feed:user:${userId}`;

        // Cache the first page for 60 seconds (Simulated Pre-computation)
        if (page === 1) {
            const cached = await getOrSet(cacheKey, async () => {
                return await FeedService._generateRun(userId, page, limit);
            }, 60);
            return cached;
        }

        return await FeedService._generateRun(userId, page, limit);
    },

    // Public: Trigger Pre-computation (e.g. from Cron)
    async precomputeFeed(userId: string) {
        await FeedService.generateFeed(userId, 1, 20); // Warms the cache
        return { success: true };
    },

    // Internal: Actual generation logic
    async _generateRun(userId: string, page = 1, limit = 20): Promise<any[]> {
        const offset = (page - 1) * limit;

        // 1. Get User's Social Graph (Who they follow)
        const currentUser = await prisma.user.findUnique({
            where: { id: userId },
            include: { following: true }
        });

        if (!currentUser) return [];

        const followingIds = currentUser.following.map(f => f.followingId);
        const userIdsToFetch = [...followingIds, userId]; // Include self

        // 2. Fetch Personal Content (Following + Self)
        // Try Cassandra first for scalable timeline
        let personalPosts: any[] = [];
        const cassandra = getCassandraClient();

        if (process.env.CASSANDRA_CONTACT_POINTS && cassandra) {
            try {
                // Simplified scatter-gather query
                // In production, we'd use a dedicated timeline table pre-written on fanout
                const query = `SELECT * FROM ${process.env.CASSANDRA_KEYSPACE || 'viewer_feed'}.posts_by_user WHERE user_id = ? LIMIT 20`;
                const promises = userIdsToFetch.map(uid => cassandra.execute(query, [uid], { prepare: true }));
                const results = await Promise.all(promises);

                // Map Cassandra rows ... (simplified for this reliable service implementation)
                // If this complex mapping is needed, we'd put it here.
                // For simplicity/reliability in this edit, let's stick to the high-level flow and fallback to Prisma if complex.
                // But let's assume we want the Prisma path for rich relations unless Cassandra is fully set up.
            } catch (e) {
                console.warn("Cassandra fetch failed", e);
            }
        }

        // Fallback/Default: Postgres (Prisma)
        if (personalPosts.length === 0) {
            personalPosts = await prisma.post.findMany({
                where: { userId: { in: userIdsToFetch } },
                include: {
                    user: { select: { username: true, avatar: true, fullName: true } },
                    likes: true,
                    comments: { include: { user: { select: { username: true } } } },
                    media: { orderBy: { order: 'asc' } },
                },
                orderBy: { createdAt: 'desc' },
                take: 50 // Fetch recent pool
            });
        }

        // 3. Fetch Suggested Content (Cached "Global Hot" Pool)
        const suggestedPool = await getOrSet('feed:suggested_pool:v1', async () => {
            return await prisma.post.findMany({
                include: {
                    user: { select: { username: true, avatar: true, fullName: true } },
                    likes: true,
                    comments: { include: { user: { select: { username: true } } } },
                    media: { orderBy: { order: 'asc' } },
                },
                orderBy: { createdAt: 'desc' }, // Recent first
                take: 100
            });
        }, 300); // 5 mins cache

        // Filter suggested (remove followed users)
        const suggestedPosts = suggestedPool
            .filter((p: any) => !userIdsToFetch.includes(p.userId))
            .slice(0, 20); // Take top 20 candidates

        // 4. Ranking & Interleaving
        const allContent = [...personalPosts, ...suggestedPosts];

        // Remove duplicates
        const uniqueContent = Array.from(new Map(allContent.map(p => [p.id, p])).values());

        // Score Function
        const now = new Date().getTime();
        const scoreItem = (item: any) => {
            const created = new Date(item.createdAt).getTime();
            const hoursAgo = Math.max(0.1, (now - created) / (1000 * 60 * 60));

            // Engagement
            const likes = item.likes ? item.likes.length : 0;
            const comments = item.comments ? item.comments.length : 0;
            const engagement = likes + (comments * 2);

            // Gravity Decay
            // (Engagement + 1) / (Time + 2)^1.8
            const score = (engagement + 1) / Math.pow(hoursAgo + 2, 1.8);

            // Relationship Boost (1.5x for following)
            const isFollowing = userIdsToFetch.includes(item.userId);
            return score * (isFollowing ? 1.5 : 1.0);
        };

        // Sort by Score
        const rankedFeed = uniqueContent.sort((a, b) => scoreItem(b) - scoreItem(a));

        // Pagination
        const pagedFeed = rankedFeed.slice(offset, offset + limit);

        return pagedFeed.map(p => ({
            ...p,
            type: 'post',
            image: p.media?.[0]?.url || '', // Support legacy 'image' prop in components
            likesCount: p.likes?.length || 0,
            commentsCount: p.comments?.length || 0,
            isLiked: p.likes?.some((l: any) => l.userId === userId)
        }));
    }
};

import { uploadToS3 } from '@/lib/s3';
import path from 'path';
import fs from 'fs';

export type MediaUploadResult = {
    url: string;
    type: 'image' | 'video';
    mimeType: string;
};

export const MediaService = {
    async processAndUpload(fileBase64: string): Promise<MediaUploadResult> {
        if (!fileBase64) {
            throw new Error('No file provided');
        }

        const matches = fileBase64.match(/^data:([A-Za-z-+\/]+);base64,(.+)$/);
        if (!matches || matches.length !== 3) {
            throw new Error('Invalid base64 string');
        }

        const mimeType = matches[1];
        const data = matches[2];
        const buffer = Buffer.from(data, 'base64');

        // Determine type and extension
        let type: 'image' | 'video' = 'image';
        let ext = 'jpg';

        if (mimeType.includes('video')) {
            type = 'video';
            ext = 'mp4';
            // In a real microservice, we would queue this for transcoding (FFmpeg)
            // e.g. await VideoEncoder.queue(buffer);
        } else if (mimeType.includes('png')) {
            ext = 'png';
        } else if (mimeType.includes('gif')) {
            ext = 'gif';
        }

        const filename = `${Date.now()}-${Math.random().toString(36).substring(7)}.${ext}`;

        // 1. Try S3 / CDN Upload
        try {
            const s3Url = await uploadToS3(buffer, filename, mimeType);
            if (s3Url) {
                return { url: s3Url, type, mimeType };
            }
        } catch (e) {
            console.warn('S3 upload failed, falling back to local storage', e);
        }

        // 2. Fallback: Base64 String Storage
        // Skip ephemeral local storage completely, so images and videos save directly
        // to the database and work instantly on Vercel without S3/Blob setup.
        console.log('Skipping local FS, returning base64 string directly for database storage');

        return {
            url: fileBase64,
            type,
            mimeType
        };
    }
};

import prisma from '@/lib/prisma';
import { User, Follows } from '@prisma/client';

// Define clear types for User Service responses
export type UserProfile = {
    id: string;
    username: string;
    fullName: string | null;
    avatar: string | null;
    bio: string | null;
    website: string | null;
    isVerified: boolean;
    followersCount: number;
    followingCount: number;
    isFollowing?: boolean;
};


export const UserService = {

    // 1. Get Profile by Username
    async getProfile(username: string, currentUserId?: string): Promise<UserProfile | null> {
        const user = await prisma.user.findUnique({
            where: { username },
            include: {
                _count: {
                    select: {
                        followedBy: true,
                        following: true,
                    }
                },
                followedBy: currentUserId ? {
                    where: { followerId: currentUserId }
                } : false
            }
        });

        if (!user) return null;

        return {
            id: user.id,
            username: user.username,
            fullName: user.fullName,
            avatar: user.avatar,
            bio: user.bio,
            website: user.website,
            isVerified: user.isVerified,
            followersCount: user._count.followedBy,
            followingCount: user._count.following,
            isFollowing: currentUserId ? user.followedBy.length > 0 : false
        };
    },

    // 2. Follow User
    async followUser(followerId: string, targetuserId: string) {
        if (followerId === targetuserId) throw new Error("Cannot follow yourself");

        // Check if already following
        const existing = await prisma.follows.findFirst({
            where: {
                followerId,
                followingId: targetuserId
            }
        });

        if (existing) return existing;

        return await prisma.follows.create({
            data: {
                followerId,
                followingId: targetuserId
            }
        });
    },

    // 3. Unfollow User
    async unfollowUser(followerId: string, targetuserId: string) {
        const existing = await prisma.follows.findFirst({
            where: {
                followerId,
                followingId: targetuserId
            }
        });

        if (!existing) return null;

        return await prisma.follows.delete({
            where: { id: existing.id }
        });
    },

    // 4. Update Profile
    async updateProfile(userId: string, data: Partial<User>) {
        // Prevent sensitive updates here if needed (e.g. password)
        const { password, id, ...safeData } = data as any;

        return await prisma.user.update({
            where: { id: userId },
            data: safeData
        });
    },

    // 5. Get Following List
    async getFollowing(userId: string) {
        return await prisma.follows.findMany({
            where: { followerId: userId },
            include: {
                following: {
                    select: {
                        id: true,
                        username: true,
                        avatar: true,
                        fullName: true
                    }
                }
            }
        });
    }
};
